<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <v-layout row>
        <v-col cols="12" sm="12" lg="12" class="pa-0 pt-2">
          <i-card-top class="d-flex" headerTitle="" :useBtnList="buttonUseList" @btnSearch="btnSearch(true)" @btnDelete="btnDelete()">
            <template v-slot:body>
              <v-layout overflow-auto> </v-layout>
            </template>
          </i-card-top>
        </v-col>
        <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
          <i-card-vertical :headerTitle="$t('memberApprovalRequestList')" device="web">
            <template v-slot:body>
              <v-layout column>
                <v-col cols="12" md="12" class="row pa-0">
                  <v-col cols="12" class="pa-0">
                    <DxDataGrid
                      id="memberApprovalDataGrid"
                      class="layout-col-height00"
                      :ref="dxDataGridRef"
                      :data-source="gridMain"
                      :remote-operations="false"
                      :hover-state-enabled="true"
                      :allow-column-reordering="true"
                      :allow-column-resizing="true"
                      :row-alternation-enabled="true"
                      :column-auto-width="true"
                      :show-borders="true"
                      :show-row-lines="true"
                      :focused-row-enabled="true"
                      key-expr="id"
                      @editing-start="onEditingStart"
                      @editor-preparing="
                        e => {
                          onEditorPreparing(e)
                          dispDateSetting(e)
                        }
                      "
                    >
                      <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />

                      <DxColumn data-field="compId" data-type="string" :visible="false" />

                      <DxColumn data-field="tuuid" data-type="number" :visible="false" />

                      <DxColumn
                        data-field="tempUserId"
                        data-type="string"
                        width="150px"
                        alignment="left"
                        :caption="$t('id')"
                        :allow-editing="false"
                      />

                      <DxColumn data-field="userPs" data-type="string" width="150px" alignment="left" :visible="false" />

                      <DxColumn data-field="userNm" data-type="string" width="80px" alignment="left" :caption="$t('name')" :allow-editing="false" />

                      <DxColumn
                        data-field="sexDiv"
                        data-type="string"
                        width="80px"
                        alignment="center"
                        :caption="$t('gender')"
                        :allow-editing="false"
                      />

                      <DxColumn
                        data-field="hireGubn"
                        data-type="string"
                        width="120px"
                        alignment="center"
                        :caption="$t('employClass')"
                        css-class="devest-grid-header-require"
                      >
                        <DxLookup :data-source="hireGubnList" value-expr="minorCd" display-expr="minorNm" />
                      </DxColumn>

                      <DxColumn data-field="hpNo" data-type="string" width="150px" alignment="left" :caption="$t('telNo')" />

                      <DxColumn
                        data-field="reqDt"
                        data-type="date"
                        width="150px"
                        alignment="center"
                        format="yyyy.MM.dd HH:mm"
                        display-format="yyyy.MM.dd"
                        :caption="$t('reqDate')"
                        :allow-editing="false"
                      />
                      <DxColumn
                        data-field="connStartDt"
                        data-type="date"
                        format="yyyy.MM.dd"
                        width="150px"
                        alignment="center"
                        :caption="$t('connStartDate')"
                        css-class="devest-grid-header-require"
                        cell-template="readDate"
                        edit-cell-template="writeDate"
                      />
                      <DxColumn
                        data-field="connEndDt"
                        data-type="date"
                        format="yyyy.MM.dd"
                        width="150px"
                        alignment="center"
                        :caption="$t('connEndDate')"
                        cell-template="readDate"
                        edit-cell-template="writeDate"
                        css-class="devest-grid-header-require"
                      />
                      <template #readDate="{ data: cellInfo }">
                        <div>
                          {{ cellInfo.text }}
                        </div>
                      </template>
                      <template #writeDate="{ data: cellInfo}">
                        <div>
                          <DxDateBox
                            :value="cellInfo.value"
                            type="date"
                            picker-type="calendar"
                            display-format="yyyy.MM.dd"
                            :read-only="cellInfo.row.data.approveStatus == 'Y' ? true : false"
                            :accept-custom-value="false"
                            :use-mask-behavior="true"
                            :max="handleDateMinMax(cellInfo, 'max')"
                            :min="handleDateMinMax(cellInfo, 'min')"
                            @opened="handleDateBox($event, cellInfo, true)"
                            @closed="handleDateBox($event, cellInfo, false)"
                            @value-changed="onDateValueChanged($event, cellInfo)"
                          />
                          <!-- input -->
                        </div>
                      </template>

                      <DxColumn
                        data-field="approveStatus"
                        data-type="string"
                        width="200px"
                        alignment="center"
                        :caption="$t('approve')"
                        cell-template="approveStatusTemplate"
                        :calculate-display-value="e => displayApproval(e)"
                        :allow-editing="false"
                      >
                      </DxColumn>
                      <template #approveStatusTemplate="{ data: cellInfo }">
                        <div v-if="cellInfo.data.approveStatus == 'N'">
                          <v-btn outlined text elevation="0" class="pa-1 pr-2 mr-1 rounded-0" width="60" height="20" @click="btnRefuse(cellInfo)">
                            <span style="font-size: 9pt;font-weight: 600;  color: #FF6464; "> {{ $t('refuse') }}</span>
                          </v-btn>
                          <v-btn @click="btnApprove(cellInfo)" outlined text elevation="0" width="60" height="20" class="pa-1 pr-2 mr-2 rounded-0">
                            <span style="font-size: 9pt;font-weight: 600;  color: #2F4F8F;"> {{ $t('approve') }}</span>
                          </v-btn>
                        </div>
                        <div v-else-if="cellInfo.data.approveStatus == 'Y'">
                          {{ cellInfo.displayValue }}
                        </div>
                        <div style="color:red;" v-else-if="cellInfo.data.approveStatus == 'R'">
                          {{ cellInfo.displayValue }}
                        </div>
                      </template>

                      <DxColumn
                        data-field="groupAuth"
                        data-type="string"
                        width="120px"
                        alignment="center"
                        :caption="$t('authGroup')"
                        css-class="devest-grid-header-require"
                      >
                        <DxLookup :data-source="groupAuthDataSource" value-expr="grpAuthCd" display-expr="grpAuthNm" />
                      </DxColumn>

                      <DxColumn data-field="remark" data-type="string" alignment="left" :caption="$t('remark')" />
                    </DxDataGrid>
                  </v-col>
                </v-col>
              </v-layout>
            </template>
          </i-card-vertical>
        </v-col>
      </v-layout>
    </v-row>
  </v-container>
</template>

<script>
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가
import { validTell } from '@/utils/validate.js'

import { DxLookup, DxPatternRule } from 'devextreme-vue/data-grid'
import DxDropDownBox from 'devextreme-vue/drop-down-box'
import DxDateBox from 'devextreme-vue/date-box'

import { getMemberApproval, saveMemberApproval, saveApprovalRefuse, deleteMemberApproval } from '@/api/baseManage/memberApprovalManage'

import { getCommonCode } from '@/api/common/commonApi'
import { getGroupData } from '@/api/setting/groupManage'

import { getFilterGroupAuthList, getDateEditorValue } from '@/utils/common.js'

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가
  name: 'memberApprovalDataGrid',
  components: {
    DxLookup,
    DxDateBox
  },
  data() {
    return {
      dxDataGridRef: 'memberApprovalDataGrid',
      buttonUseList: [
        'btnSearch', //조회
        // 'btnSave', //저장
        'btnDelete' //삭제
      ],
      gridMain: [],
      hireGubnList: [],
      groupAuthList: [],
      groupAuthDataSource: [],
      phonePattern: /^\d{3}-(\d{4}||\d{3})-\d{4}$/i
    }
  },
  computed: {},
  beforeMount() {},
  activated() {
    this.setComboBoxData()
  },
  mounted() {
    // 켜질때 조회
    this.btnSearch(true)
  },
  methods: {
    btnSearch(isNotify) {
      this.openLoading('searching')

      let param = {
        compId: this.getCompId()
      }

      this.companys = []
      getMemberApproval(param, isNotify)
        .then(res => {
          if (res.success) {
            this.gridInit(this.GetDataGrid(this.dxDataGridRef))
            this.gridMain = []
            this.gridMain = res.list
            // 승인요청시 default는 근로자임
            this.gridMain.forEach(element => {
              if (element.approveStatus == 'N') {
                element.groupAuth = 'normal'
              }
            })
            this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
          }
        })
        .catch(error => {})
        .finally(() => {
          this.endLoading()
        })
    },

    btnRefuse(cellInfo) {
      this.vToastifyPrompt(
        this.$t(`[${cellInfo.data.tempUserId}:${cellInfo.data.userNm}] 승인거절 하시겠습니까?`),
        'info',
        current => {
          let source = this.GetDataGrid(this.dxDataGridRef).getDataSource()
          let items = source.items()
          this.GetDataGrid(this.dxDataGridRef).beginUpdate()
          this.GetDataGrid(this.dxDataGridRef).saveEditData()

          cellInfo.data.approveStatus = 'R'
          //저장 api
          let saveData = []
          saveData.push(cellInfo.data)
          this.openLoading('saving')
          saveApprovalRefuse(saveData, true)
            .then(res => {
              if (res.success) {
                this.btnSearch(false)
              }
            })
            .catch(error => {})
            .finally(() => {
              this.GetDataGrid(this.dxDataGridRef).endUpdate()
              this.endLoading()
            })
        },
        null,
        true
      )
    },
    btnApprove(cellInfo) {
      let data = cellInfo.data
      this.vToastifyPrompt(
        this.$t(`[${data.tempUserId}:${data.userNm}] 승인 하시겠습니까?`),
        'info',
        current => {
          const valid = ['hireGubn', 'connStartDt', 'connEndDt', 'groupAuth']
          if (valid.some(el => !data[el] || data[el].trim == '')) {
            this.vToastify(
              `${this.$t('msgReqValidate')} [${this.$t('employClass')},${this.$t('connStartDate')},${this.$t('connEndDate')}],${this.$t(
                'authGroup'
              )}`,
              'warn'
            )
            return
          }

          //유효성 검사
          if (data.hpNo === null || !validTell(data.hpNo)) {
            this.vToastify(this.$t('올바르지 않은 전화번호 형식입니다.'), 'warn')
            return
          }
          if (data.connStartDt > data.connEndDt) {
            this.vToastify(this.$t('접속허용 종료일은 접속허용 시작일보다 이후여야 합니다.'), 'warn')
            return
          }
          data.approveStatus = 'Y'
          //저장 api
          this.openLoading('saving')
          saveMemberApproval([data], true)
            .then(res => {
              if (res.success) {
                this.btnSearch(false)
              }
            })
            .catch(error => {})
            .finally(() => {
              this.endLoading()
            })
        },
        null,
        true
      )
    },
    btnDelete() {
      this.GetDataGrid(this.dxDataGridRef)
        .getSelectedRowsData()
        .then(selectedRows => {
          if (selectedRows.length === 0) {
            this.vToastify(this.$t('selectionData'), 'warn')
            return
          }
          this.vToastifyPrompt(
            this.$t('doDeleteData'),
            'info',
            current => {
              this.GetDataGrid(this.dxDataGridRef).beginUpdate()
              this.GetDataGrid(this.dxDataGridRef).saveEditData()

              this.openLoading('deleting')
              //삭제 api
              deleteMemberApproval(selectedRows, true)
                .then(res => {
                  if (res.success) {
                    this.deleteCallBack(selectedRows)
                    this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
                  }
                })
                .catch(error => {})
                .finally(() => {
                  this.GetDataGrid(this.dxDataGridRef).endUpdate()
                  this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
                  this.endLoading()
                })
            },
            null,
            true
          )
        })
    },

    ///////////////////////////////////////
    /*           DataGrid Event          */
    ///////////////////////////////////////
    onEditingStart(e) {
      if (
        e.data.approveStatus == 'R' &&
        (e.column.dataField == 'connStartDt' ||
          e.column.dataField == 'connEndDt' ||
          e.column.dataField == 'groupAuth' ||
          e.column.dataField == 'hpNo' ||
          e.column.dataField == 'hireGubn')
      ) {
        e.cancel = true
        return
      }
    },
    ///////////////////////////////////////
    /*             etc Event             */
    ///////////////////////////////////////
    deleteCallBack(param) {
      var index = null
      param.forEach(key => {
        index = this.gridMain.findIndex(obj => obj == key)
        this.gridMain.splice(index, 1)
      })
    },
    setComboBoxData() {
      this.openLoading()
      Promise.all([
        getCommonCode('C0074'), //고용구분
        getGroupData() //권한그룹
      ])
        .then(response => {
          if (response.length) {
            this.hireGubnList = response[0].list.slice()
            this.groupAuthDataSource = getFilterGroupAuthList(response[1], this.getCompId())
          }
        })
        .finally(() => {
          this.endLoading()
        })
    },
    displayApproval(element) {
      if (element.approveStatus == 'Y') {
        return `승인 (${element.updatedAt})`
      } else if (element.approveStatus == 'R') {
        return `승인거절 (${element.updatedAt})`
      } else {
        return
      }
    },
    dispDateSetting(e) {
      //connStartDt connEndDt
      if (e.parentType == 'dataRow') {
        if (e.dataField == 'connStartDt') {
          e.editorOptions.max = e.row.data.connEndDt
        } else if (e.dataField == 'connEndDt') {
          e.editorOptions.min = e.row.data.connStartDt
        }
      }
    },
    onDateValueChanged(event, cellInfo) {
      //날짜 세팅
      let currentDate = getDateEditorValue(event.value)

      //그리드 삽입
      this.GetDataGrid(this.dxDataGridRef).beginUpdate()
      const cell = this.gridMain[cellInfo.rowIndex]
      cell[cellInfo.column.dataField] = currentDate
      cellInfo.setValue(currentDate)
      this.$refs[this.dxDataGridRef].instance.selectRows(cellInfo.row.key, true)
      this.GetDataGrid(this.dxDataGridRef).saveEditData()
      this.GetDataGrid(this.dxDataGridRef).endUpdate()
    },
    handleDateMinMax(cellInfo, type) {
      const row = this.gridMain[cellInfo.rowIndex]
      if (!row) return undefined
      const dateField = type === 'max' ? 'connEndDt' : 'connStartDt'
      return row[dateField] ? new Date(row[dateField]) : undefined
    },
    handleDateBox(event, cellInfo, isOpened) {
      const { dataField } = cellInfo.column
      const range = dataField == 'connStartDt' ? 'min' : 'max'
      event.component.option(range, isOpened ? null : new Date(cellInfo.text))
    }
  }
}
</script>

<style scoped></style>
